export function getOktaEnv(location: string) {
  if (location === undefined)
    throw new Error(`No redirection location provided.`);

  const locationTokens = location.replace('https://', '').split('/');

  if (locationTokens.length < 3)
    throw new Error(`Unexpected redirection format: ${location}.`);

  const oktaEnv = locationTokens[0];

  if (['sso.renault.com', 'sso-uat.renault.com'].indexOf(oktaEnv) == -1)
    throw new Error(`Unexpected Okta environment '${oktaEnv}'.`);

  return {
    oktaEnv,
    oktaAuthzURL: `https://${oktaEnv}/oauth2/${locationTokens[2]}/v1/authorize`,
  };
}
